oded\";a:1:{i:0;a:5:{s:4:\"data\";s:9050:\"\n<figure class=\"wp-block-image aligncenter size-large\"><a href=\"https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX.jpg\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"576\" src=\"https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX-1024x576.jpg\" alt=\"\" class=\"wp-image-1172\" srcset=\"https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX-1024x576.jpg 1024w, https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX-300x169.jpg 300w, https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX-768x432.jpg 768w, https://vi.wordpress.org/files/2024/08/Nha-Trang-WordPress-Meetup-2024-08-25-FIX.jpg 1200w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2b50.png\" alt=\"⭐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Đăng ký tham dự Nha Trang WordPress Meetup 25/08/2024 <img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2b50.png\" alt=\"⭐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Xin chào tất cả mọi người, vậy là Nha Trang WordPress Meetup đã quay trở lại sau nhiều tháng gián đoạn, Meetup 25/08/2024 sẽ diễn ra để chào mừng sinh nhật lần 21 và phiên bản mới nhất WordPress 6.6.1 của mã nguồn mở xây dựng website phổ biến nhất thế giới WordPress tại thành phố biển Nha Trang.</p>\n\n\n\n<p class=\"wp-block-paragraph\">WordPress là nền tảng xuất bản mã nguồn mở được hàng triệu trang web trên toàn thế giới lựa chọn—từ người sáng tạo và doanh nghiệp nhỏ đến các doanh nghiệp lớn.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Lần này Ban tổ chức sẽ mang đến cho toàn thể các bạn yêu mến WordPress tại Nha Trang các chủ đề hấp dẫn như sau</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f4a5.png\" alt=\"💥\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Chủ đề 1: Quy trình xử lý mã độc cho website WordPress</strong><br>Speaker: Nguyễn Xuân Bình Minh &#8211; CEO Minh Duy Solutions</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f4a5.png\" alt=\"💥\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Chủ đề 2: Bí quyết x10 doanh số với chiến lược phễu bán hàng trong WordPress</strong><br>Speaker: Nguyễn Minh Phụng &#8211; CEO Công ty TNHH Giải Pháp ETI</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f4a5.png\" alt=\"💥\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Chủ đề 3: 5 Ways to increase your Businesses Profits</strong><br>Speaker: Hà Anh Lĩnh &#8211; CEO Công ty TNHH TM &amp; DV ANHLINHMKT</p>\n\n\n\n<p class=\"wp-block-paragraph\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /><strong> Hình thức: </strong>Offline</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Thời gian tổ chức: 08h30 ngày 25/08/2024</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Địa điểm: </strong>Stockholm Bistro &amp; Co-working<br>43 Lý Tự Trọng, Thành phố Nha Trang, Khánh Hoà<br>Google Maps: <a href=\"https://g.co/kgs/Ke3J66q\">https://g.co/kgs/Ke3J66q</a> </p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Phí tham dự:</strong><br>&#8211; Miễn phí tham dự<br>&#8211; Số lượng tối đa: 30 người</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Đăng ký tham dự tại: </strong> <a href=\"https://forms.gle/5in6wkP7Yjn1jhT9A\" target=\"_blank\" rel=\"noreferrer noopener\">https://forms.gle/5in6wkP7Yjn1jhT9A</a></p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Đơn vị tài trợ chính:</strong><br><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2b50.png\" alt=\"⭐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Công ty TNHH Xây Dựng &amp; Công Nghệ Quỳnh An (<a href=\"https://www.solar-nhatrang.com/\" data-type=\"link\" data-id=\"https://www.solar-nhatrang.com/\" target=\"_blank\" rel=\"noreferrer noopener\">Quỳnh An Solar</a>)<br><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/2b50.png\" alt=\"⭐\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> CÔNG TY CỔ PHẦN FUTE (<a href=\"https://web2m.com/\" data-type=\"link\" data-id=\"https://web2m.com/\" target=\"_blank\" rel=\"noreferrer noopener\">Web2M</a> &amp; <a href=\"https://pay2s.vn/\" data-type=\"link\" data-id=\"https://pay2s.vn/\" target=\"_blank\" rel=\"noreferrer noopener\">Pay2S</a>)</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Đơn vị tổ chức: <a href=\"https://minhduy.vn/\" data-type=\"link\" data-id=\"https://minhduy.vn/\" target=\"_blank\" rel=\"noreferrer noopener\">Minh Duy Solutions</a></strong></p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Các kênh truyền thông khác</strong><br>&#8211; Meetup: <a href=\"https://www.meetup.com/nha-trang-marketing-meetup/events/302732875/\">https://www.meetup.com/nha-trang-marketing-meetup/events/302732875/</a><br>&#8211; Facebook Event: <a href=\"https://www.facebook.com/events/1864084187435658/\">https://www.facebook.com/events/1864084187435658/</a> </p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Câu hỏi thường gặp</strong><br><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f449.png\" alt=\"👉\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Nha Trang WordPress Meetup là hoạt động offline hàng tháng nhằm phát triển cộng đồng yêu thích và sử dụng WordPress tại Nha Trang<br><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f449.png\" alt=\"👉\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Nha Trang WordPress Meetup là LOCAL GROUP chính thức được công nhận bởi WordPress.Org hoạt động từ năm 2016.<br><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f449.png\" alt=\"👉\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Nha Trang WordPress Meetup là chương trình hoàn toàn miễn phí, không thu phí tham dự đối với người tham gia (Trừ một số trường hợp phải hỗ trợ Ban tổ chức chi phí thuê địa điểm tổ chức meetup)</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> The Five Good Faith Rules</strong><br>5 Nguyên tắc đảm bảo các group theo tinh thần Của WordPress khi tổ chức meetup xây dựng cộng đồng<br>&#8211; Phi lợi nhuận: Hướng tới cả cộng đồng, không phục vụ cho một tổ chức kinh doanh nào.<br>&#8211; Mọi người đều được tham gia, không phân biệt về tiền bạc, khả năng về lập trình…<br>&#8211; Không trả tiền cho Speakers, nếu có chi phí thêm thì chỉ là những chi phí cho meetup như thuê địa điểm, nước uống.<br>&#8211; Các meetup có thể do bất cứ ai trong group mà có thể tin tưởng được để tổ chức.<br>&#8211; Không có các hành động xúc phạm về bất cứ ai, bất cứ vấn đề gì trong meetup.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><img src=\"https://s.w.org/images/core/emoji/17.0.2/72x72/1f3af.png\" alt=\"🎯\" class=\"wp-smiley\" style=\"height: 1em; max-height: 1em;\" /> Lưu ý:<br>– Các sản phẩm mà không có GPL thì không được phép trình bày tại meetup<br>– Không giới thiệu kiểu sale, bán các sản phẩm mà vi phạm bản quyền.</p>\n\n\n\n<p class=\"wp-block-paragraph\"><br>#NhaTrangWordPress #MeetUp #NhaTrang #WordPress</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:95:\"https://vi.wordpress.org/2024/08/09/dang-ky-tham-du-nha-trang-wordpress-meetup-25-08-2024/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1161\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:5;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"Hà Nội WordPress Meetup tháng 04.2024\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://vi.wordpress.org/2024/04/08/ha-noi-wordpress-meetup-thang-04-2024/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:82:\"https://vi.wordpress.org/2024/04/08/ha-noi-wordpress-meetup-thang-04-2024/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Mon, 08 Apr 2024 03:22:23 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:22:\"Hanoi WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1146\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:346:\"Sự kiện dành cho các bạn quan tâm tới cách sử dụng WordPress ở mức độ mới tìm hiểu. Trong buổi Meetup lần này, bạn sẽ được tham gia buổi giới thiệu về WordPress, những gì cơ bản nhất để tiếp cận WordPress và sử dụng nó để làm blog, trang giới thiệu cơ bản [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:1634:\"\n<p class=\"wp-block-paragraph\">Sự kiện dành cho các bạn quan tâm tới cách sử dụng WordPress ở mức độ mới tìm hiểu. Trong buổi Meetup lần này, bạn sẽ được tham gia buổi giới thiệu về WordPress, những gì cơ bản nhất để tiếp cận WordPress và sử dụng nó để làm blog, trang giới thiệu cơ bản hoặc thậm chí là website bán hàng.</p>\n\n\n\n<span id=\"more-1146\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Địa điểm</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Tầng 5, Toà nhà Đinh Trọng Dật, Đường CN1, Xuân Phương, Bắc Từ Liêm, Hà Nội (<a href=\"https://maps.app.goo.gl/GodtTVGattFQGdnE9\" data-type=\"link\" data-id=\"https://maps.app.goo.gl/GodtTVGattFQGdnE9\">xem bản đồ</a>)</p>\n\n\n\n<p class=\"wp-block-paragraph\"><em>Cảm ơn đơn vị hỗ trợ về địa điểm: <strong><a href=\"https://itci.edu.vn/\">Viện Đào Tạo Và Hợp Tác Quốc Tế ITCI &#8211; Đại học Công Nghệ Đông Á</a></strong>. </em></p>\n\n\n\n<h2 class=\"wp-block-heading\">Lịch trình dự kiến</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li>18:00 – 18:15: Networking</li>\n\n\n\n<li>18:15 – 18:45: Điểm tin WordPress</li>\n\n\n\n<li>18:45 &#8211; 19:15: Sử dụng WordPress cơ bản</li>\n\n\n\n<li>19:15 &#8211; 19:45: Thảo luận mở về WordPress</li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Đăng ký tham gia</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Để việc chuẩn bị được tốt nhất, các bạn <a href=\"https://www.meetup.com/hanoi-wordpress-meetup/events/300180394/\">đăng ký tham dự tại trang chính thức Meetup</a>.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://vi.wordpress.org/2024/04/08/ha-noi-wordpress-meetup-thang-04-2024/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1146\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:6;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"Hà Nội WordPress Meetup tháng 01.2024\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://vi.wordpress.org/2024/01/04/ha-noi-wordpress-meetup-thang-01-2024/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:82:\"https://vi.wordpress.org/2024/01/04/ha-noi-wordpress-meetup-thang-01-2024/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Thu, 04 Jan 2024 13:05:01 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:22:\"Hanoi WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1136\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:350:\"Những ai đang sử dụng và yêu thích WordPress lại có cơ hội gặp nhau tại buổi meetup đầu tiên của năm 2024, được tổ chức bởi cộng đồng WordPress tiếng Việt. Thời gian và địa điểm Đăng ký tham gia Hãy đăng ký trước để đảm bảo có vị trí ngồi trong buổi meetup. [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2763:\"\n<p class=\"wp-block-paragraph\">Những ai đang sử dụng và yêu thích WordPress lại có cơ hội gặp nhau tại buổi meetup đầu tiên của năm 2024, được tổ chức bởi cộng đồng WordPress tiếng Việt.</p>\n\n\n\n<span id=\"more-1136\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Thời gian và địa điểm</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Thời gian: <strong>08:30 &#8211; 11:30 ngày 06.01.2024</strong></li>\n\n\n\n<li>Địa điểm: Trường CĐ Việt Mỹ (Cơ sở 2) &#8211; Coworking tầng 5, <strong>số 39 Hoàng Quán Chi, Cầu Giấy</strong>, Hà Nội (gần CV Cầu Giấy) &#8211; <a href=\"https://maps.app.goo.gl/z1xVwgVEAD5bzYny5\" data-type=\"link\" data-id=\"https://maps.app.goo.gl/z1xVwgVEAD5bzYny5\">link bản đồ</a></li>\n</ul>\n\n\n\n<h2 class=\"wp-block-heading\">Đăng ký tham gia</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Hãy đăng ký trước để đảm bảo có vị trí ngồi trong buổi meetup.</p>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link has-vivid-red-background-color has-background wp-element-button\" href=\"https://forms.gle/9oqvSJDm6pAhfZtCA\">Đăng ký tham gia meetup</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Các chủ đề trong chương trình</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Build Your GeneratePress Theme</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Speaker: Nguyễn Minh Khôi (Founder/CEO <strong>Code Tốt</strong> &#8211; Locale Manager &#8211; WordPress tiếng Việt)</p>\n\n\n\n<h3 class=\"wp-block-heading\">Build a website with YooTheme Builder Framework</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Speaker: Vũ Mạnh Tiến (Founder/CEO Jupiter Media)</p>\n\n\n\n<h3 class=\"wp-block-heading\">Make Money from Google Adsense</h3>\n\n\n\n<p class=\"wp-block-paragraph\">Speaker: Nguyễn Công Minh (Founder SEO Thành Công)</p>\n\n\n\n<blockquote class=\"wp-block-quote is-layout-flow wp-block-quote-is-layout-flow\">\n<p class=\"wp-block-paragraph\">Ngoài ra, còn một phiên thảo luận tự do về WordPress và các vấn đề liên quan dành cho các bạn tham gia.</p>\n</blockquote>\n\n\n\n<h2 class=\"wp-block-heading\">Tổ chức cùng đồng hành với Meetup</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Dù đây là chương trình không thu phí, BTC xin cảm ơn sự đồng hành của các đơn vị nhằm giúp chương trình diễn ra có chất lượng hơn.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Trường Cao đẳng Việt Mỹ (hỗ trợ địa điểm và tình nguyện viên)</li>\n\n\n\n<li><a href=\"https://hazomedia.com/\" data-type=\"link\" data-id=\"https://hazomedia.com/\">HazoMedia</a></li>\n\n\n\n<li>HostVN</li>\n\n\n\n<li>VietCham Singapore (quà tặng)</li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://vi.wordpress.org/2024/01/04/ha-noi-wordpress-meetup-thang-01-2024/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1136\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:7;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:41:\"Sài Gòn WordPress Meetup tháng 08.2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:69:\"https://vi.wordpress.org/2023/08/02/sai-gon-wordpress-meetup-08-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:77:\"https://vi.wordpress.org/2023/08/02/sai-gon-wordpress-meetup-08-2023/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 02 Aug 2023 03:14:05 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:26:\"Sài Gòn WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1088\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:342:\"Vào ngày 19.08.2023 tới đây, những người yêu thích WordPress tại Sài Gòn sẽ cùng nhau gặp gỡ và chia sẻ về các chủ đề thú vị. Thời gian 13:30 &#8211; 17:30 ngày 19.08.2023 Địa điểm 8 Trần Quang Diệu, phường 14, quận 3, TP. HCM Nội dung thảo luận Chủ đề 1: Tối ưu [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:2574:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"577\" src=\"https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-1024x577.png\" alt=\"\" class=\"wp-image-1089\" srcset=\"https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-1024x577.png 1024w, https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-300x169.png 300w, https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-768x433.png 768w, https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023-1536x865.png 1536w, https://vi.wordpress.org/files/2023/08/saigon-wp-meetup-082023.png 1640w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Vào ngày 19.08.2023 tới đây, những người yêu thích WordPress tại Sài Gòn sẽ cùng nhau gặp gỡ và chia sẻ về các chủ đề thú vị.</p>\n\n\n\n<span id=\"more-1088\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Thời gian</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>13:30 &#8211; 17:30</strong> ngày <strong>19.08.2023</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Địa điểm</h2>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>8 Trần Quang Diệu, phường 14, quận 3, TP. HCM</strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Nội dung thảo luận</h2>\n\n\n\n<h3 class=\"wp-block-heading\">Chủ đề 1: Tối ưu tốc độ website WordPress</h3>\n\n\n\n<p class=\"has-medium-font-size wp-block-paragraph\"><strong>Khôi Nguyễn</strong></p>\n\n\n\n<p class=\"has-small-font-size wp-block-paragraph\">Founder/CEO <strong><a href=\"https://codetot.vn/ve-code-tot/\">Code Tốt</a></strong><br>CTO <strong>Nhà Phố Net</strong><br>Locale Manager tại <strong>WordPress tiếng Việt</strong><br>Admin nhóm <strong><a href=\"https://www.facebook.com/groups/toiuuweb\">Tối ưu Web</a></strong></p>\n\n\n\n<h2 class=\"wp-block-heading\">Đăng ký tham gia Meetup</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Bạn vào nhóm Zalo <a href=\"https://zalo.me/g/hblyng586\" data-type=\"link\" data-id=\"https://zalo.me/g/hblyng586\">WordPress Meetup Sài Gòn</a> để vote chủ đề yêu thích.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Đơn vị tài trợ và đồng hành</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li><a href=\"https://123host.vn\" data-type=\"link\" data-id=\"https://123host.vn\">123Host</a></li>\n\n\n\n<li><a href=\"https://interdata.vn/\">InterData</a></li>\n\n\n\n<li><a href=\"https://vietnix.vn/\">Vietnix</a></li>\n\n\n\n<li>Giải Pháp SEO</li>\n\n\n\n<li>In Hương Giang</li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://vi.wordpress.org/2023/08/02/sai-gon-wordpress-meetup-08-2023/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1088\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:8;a:6:{s:4:\"data\";s:76:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:38:\"Online Meetup Nha Trang tháng 08.2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:74:\"https://vi.wordpress.org/2023/08/02/online-meetup-nha-trang-thang-08-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:83:\"https://vi.wordpress.org/2023/08/02/online-meetup-nha-trang-thang-08-2023/#comments\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Wed, 02 Aug 2023 02:54:30 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:2:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:26:\"Nha Trang WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1085\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:355:\"Vào ngày 13/08/2023, những người yêu thích WordPress tại Nha Trang sẽ tổ chức một buổi thảo luận để kết nối mọi người đã, đang và sẽ sử dụng WordPress tại Nha Trang sau một thời gian dài tạm dừng hoạt động meetup do COVID. Các chủ đề thảo luận Topic 1: Kinh nghiệm tối [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:3158:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"538\" src=\"https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-1024x538.png\" alt=\"\" class=\"wp-image-1086\" srcset=\"https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-1024x538.png 1024w, https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-300x158.png 300w, https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-768x403.png 768w, https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-1536x807.png 1536w, https://vi.wordpress.org/files/2023/08/nhatrang-meetup-082023-2048x1075.png 2048w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Vào ngày 13/08/2023, những người yêu thích WordPress tại Nha Trang sẽ tổ chức một buổi thảo luận để kết nối mọi người đã, đang và sẽ sử dụng WordPress tại Nha Trang sau một thời gian dài tạm dừng hoạt động meetup do COVID.</p>\n\n\n\n<span id=\"more-1085\"></span>\n\n\n\n<h2 class=\"wp-block-heading\">Các chủ đề thảo luận</h2>\n\n\n\n<h3 class=\"wp-block-heading has-medium-font-size\"><strong>Topic 1: Kinh nghiệm tối ưu website WordPress mới nhất</strong></h3>\n\n\n\n<p class=\"has-medium-font-size wp-block-paragraph\"><strong>Khôi Nguyễn</strong></p>\n\n\n\n<p class=\"has-small-font-size wp-block-paragraph\">Founder/CEO&nbsp;<strong><a href=\"https://codetot.vn/ve-code-tot/\">Code Tốt</a></strong><br>CTO&nbsp;<strong>Nhà Phố Net</strong><br>Locale Manager tại&nbsp;<strong>WordPress tiếng Việt</strong><br>Admin nhóm&nbsp;<strong><a href=\"https://www.facebook.com/groups/toiuuweb\">Tối ưu Web</a></strong></p>\n\n\n\n<h3 class=\"wp-block-heading\"><strong>Topic 2: Thiết Kế Website với WordPress dành cho Marketer</strong></h3>\n\n\n\n<p class=\"wp-block-paragraph\"><a href=\"https://vominhhuy.com/\" data-type=\"link\" data-id=\"https://vominhhuy.com/\"><strong>Võ Minh Huy</strong></a></p>\n\n\n\n<p class=\"has-small-font-size wp-block-paragraph\">Founder <a href=\"https://tadateam.com/\" data-type=\"link\" data-id=\"https://tadateam.com/\">TADA</a></p>\n\n\n\n<h2 class=\"wp-block-heading\">Thời gian</h2>\n\n\n\n<p class=\"wp-block-paragraph\">08h30 – 11h00 ngày 13/08/2023 (GMT +7)</p>\n\n\n\n<h2 class=\"wp-block-heading\">Địa điểm</h2>\n\n\n\n<p class=\"wp-block-paragraph\">Trực tuyến qua Google Meet hoặc Zoom (sẽ thông báo qua email)</p>\n\n\n\n<p class=\"wp-block-paragraph\">Hãy gia nhập trên <a href=\"https://zalo.me/g/uhmmlm126\">nhóm Zalo</a> để nhận cập nhật liên kết tham gia.</p>\n\n\n\n<h2 class=\"wp-block-heading\">Đăng ký tham gia</h2>\n\n\n\n<div class=\"wp-block-buttons is-layout-flex wp-block-buttons-is-layout-flex\">\n<div class=\"wp-block-button\"><a class=\"wp-block-button__link wp-element-button\" href=\"https://forms.gle/4zxDZUb8jNLBFboY8\">Đăng ký tham gia</a></div>\n</div>\n\n\n\n<h2 class=\"wp-block-heading\">Đồng tổ chức</h2>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Hỗ trợ tổ chức sự kiện: <a href=\"https://minhduy.vn\">Minh Duy Solutions</a>.</li>\n</ul>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:79:\"https://vi.wordpress.org/2023/08/02/online-meetup-nha-trang-thang-08-2023/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"1\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1085\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}i:9;a:6:{s:4:\"data\";s:79:\"\n		\n		\n					\n		\n		\n		\n				\n		\n		\n		\n\n					\n										\n					\n					\n			\n		\n		\n			\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";s:5:\"child\";a:6:{s:0:\"\";a:7:{s:5:\"title\";a:1:{i:0;a:5:{s:4:\"data\";s:48:\"Recap: WordPress Meetup Hà Nội tháng 07/2023\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:80:\"https://vi.wordpress.org/2023/07/22/recap-wordpress-meetup-ha-noi-thang-07-2023/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:88:\"https://vi.wordpress.org/2023/07/22/recap-wordpress-meetup-ha-noi-thang-07-2023/#respond\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:7:\"pubDate\";a:1:{i:0;a:5:{s:4:\"data\";s:31:\"Sat, 22 Jul 2023 22:53:23 +0000\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:8:\"category\";a:3:{i:0;a:5:{s:4:\"data\";s:6:\"Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:1;a:5:{s:4:\"data\";s:22:\"Hanoi WordPress Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}i:2;a:5:{s:4:\"data\";s:12:\"Recap Meetup\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:4:\"guid\";a:1:{i:0;a:5:{s:4:\"data\";s:32:\"https://vi.wordpress.org/?p=1078\";s:7:\"attribs\";a:1:{s:0:\"\";a:1:{s:11:\"isPermaLink\";s:5:\"false\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:11:\"description\";a:1:{i:0;a:5:{s:4:\"data\";s:341:\"Cảm ơn anh chị em đã tham dự WordPress Meetup tại Hà Nội tháng 07/2023. Đã tròn một năm mới thấy sự quay trở lại của Meetup, và sự nhiệt thành, cùng nhau đóng góp, trao đổi đã khơi dậy rất nhiều năng lượng cho mỗi người. Trong buổi hôm nay, đại diện từ Code [&#8230;]\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:32:\"http://purl.org/dc/elements/1.1/\";a:1:{s:7:\"creator\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"Khoi Pro\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:40:\"http://purl.org/rss/1.0/modules/content/\";a:1:{s:7:\"encoded\";a:1:{i:0;a:5:{s:4:\"data\";s:6073:\"\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/07/image-2.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"767\" src=\"https://vi.wordpress.org/files/2023/07/image-2-1024x767.png\" alt=\"WordPress Meetup Hà Nội tháng 07/2023\" class=\"wp-image-1081\" srcset=\"https://vi.wordpress.org/files/2023/07/image-2-1024x767.png 1024w, https://vi.wordpress.org/files/2023/07/image-2-300x225.png 300w, https://vi.wordpress.org/files/2023/07/image-2-768x575.png 768w, https://vi.wordpress.org/files/2023/07/image-2-440x330.png 440w, https://vi.wordpress.org/files/2023/07/image-2.png 1276w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Cảm ơn anh chị em đã tham dự WordPress Meetup tại Hà Nội tháng 07/2023. Đã tròn một năm mới thấy sự quay trở lại của Meetup, và sự nhiệt thành, cùng nhau đóng góp, trao đổi đã khơi dậy rất nhiều năng lượng cho mỗi người.</p>\n\n\n\n<span id=\"more-1078\"></span>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/07/image.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"569\" src=\"https://vi.wordpress.org/files/2023/07/image-1024x569.png\" alt=\"Tối ưu Web mới nhất từ Code Tốt\" class=\"wp-image-1079\" srcset=\"https://vi.wordpress.org/files/2023/07/image-1024x569.png 1024w, https://vi.wordpress.org/files/2023/07/image-300x167.png 300w, https://vi.wordpress.org/files/2023/07/image-768x427.png 768w, https://vi.wordpress.org/files/2023/07/image.png 1094w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Trong buổi hôm nay, đại diện từ Code Tốt đã chia sẻ những định hướng tối ưu web hiệu quả và có mục, đúng mục đích, đạt kết quả. Đó không chỉ là việc tối ưu PageSpeed Web, mà là tổng thể phải xác định mục tiêu dùng website vào việc gì và các bước tiến hành ra sao.</p>\n\n\n\n<figure class=\"wp-block-image size-large\"><a href=\"https://vi.wordpress.org/files/2023/07/image-1.png\"><img loading=\"lazy\" decoding=\"async\" width=\"1024\" height=\"572\" src=\"https://vi.wordpress.org/files/2023/07/image-1-1024x572.png\" alt=\"Tìm hiểu về ReactJS, NextJS\" class=\"wp-image-1080\" srcset=\"https://vi.wordpress.org/files/2023/07/image-1-1024x572.png 1024w, https://vi.wordpress.org/files/2023/07/image-1-300x168.png 300w, https://vi.wordpress.org/files/2023/07/image-1-768x429.png 768w, https://vi.wordpress.org/files/2023/07/image-1.png 1291w\" sizes=\"auto, (max-width: 1024px) 100vw, 1024px\" /></a></figure>\n\n\n\n<p class=\"wp-block-paragraph\">Ở phần chia sẻ của anh Hoàng từ Melisoft về mô hình NextJS sử dụng API từ bên thứ ba (như WordPress REST API), tập trung vào việc xoay quanh mô hình mô-đun hoá, tinh chỉnh liên tục, tạo ra những nền tảng có mức độ tái sử dụng cao. Anh Hoàng cũng đã giới thiệu một số kiến trúc được phát triển và tạo ra MeliPlatform khá thú vị, nhận được sự quan tâm của mọi người thông qua số câu hỏi.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Một số câu hỏi khác về WordPress cũng được giải đáp và trao đổi khá nhiệt tình.</p>\n\n\n\n<ul class=\"wp-block-list\">\n<li>Việc định kỳ nâng cấp website WordPress là cần thiết, đặc biệt là các phiên bản Minor (định dạng x.x.[x]). Các phiên bản Major thì cần tiến hành sao lưu trước khi nâng cấp.</li>\n\n\n\n<li>Nên sử dụng các plugin bảo mật giúp hạn chế tấn công như Wordfence.</li>\n\n\n\n<li>Việc sử dụng kết hợp giữa NextJS và WP REST API có những mục tiêu cụ thể, đặc biệt là phải quan tâm tới đối tượng sử dụng chính là ai.</li>\n\n\n\n<li>Xu hướng ChatGPT áp dụng trong công việc digital marketing.</li>\n\n\n\n<li>Việc tối ưu website phụ thuộc nhiều vào tài nguyên, chi phí, và có nhiều giải pháp khác nhau. Tuy nhiên, việc hướng tới phát triển với nguồn lực đầu tư phù hợp là hướng đi đúng đắn nhất cho doanh nghiệp.</li>\n</ul>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Tham gia các sự kiện tiếp theo</strong></p>\n\n\n\n<p class=\"wp-block-paragraph\">Các Meetup tiếp theo tại Hà Nội được công bố trên nhóm Zalo: <a href=\"https://zalo.me/g/gfqysr978\">https://zalo.me/g/gfqysr978</a> (nơi bạn sẽ được chọn chủ đề, thời gian, địa điểm).</p>\n\n\n\n<p class=\"wp-block-paragraph\"><strong>Slide chương trình:</strong><br>&#8211; <a href=\"https://docs.google.com/presentation/d/1ZNT9RDVyoBHXYN08LusDfeAKp1RCGYsm1OZBVDUZJm8/edit?fbclid=IwAR39tITgZOJHvC_j2u-Ty7I3SpIZXagPce8mIlZVxmsCKDkr9av4O73tN5I\" data-type=\"link\" data-id=\"https://docs.google.com/presentation/d/1ZNT9RDVyoBHXYN08LusDfeAKp1RCGYsm1OZBVDUZJm8/edit?fbclid=IwAR39tITgZOJHvC_j2u-Ty7I3SpIZXagPce8mIlZVxmsCKDkr9av4O73tN5I\">Tối ưu web mới nhất</a>, từ Mr. Khôi (Founder/CEO Code Tốt)<br>&#8211; Chia sẻ về <a href=\"https://www.figma.com/proto/hLFfSDh2GihHNAhPDyMA5w/Melisoft---Reactjs\">React+NextJS</a> từ Mr. Hoàng (Founder/CEO Melisoft) <br>&#8211; Quà tặng thêm 1 bài viết về <a href=\"https://codetot.vn/inp/\" data-type=\"link\" data-id=\"https://codetot.vn/inp/\">INP</a> để mọi người đọc lược qua nội dung cập nhật mới nhất.</p>\n\n\n\n<p class=\"wp-block-paragraph\">Cảm ơn phần tài trợ nước uống từ nhà cung cấp Hosting InterData, tài trợ địa điểm của <a href=\"https://codetot.vn/ve-code-tot/\">Code Tốt</a>, sự tham gia từ các cộng đồng <strong>Yêu SEO</strong>, <strong>SEO Meetup</strong>, <strong>CxO Hà Nội</strong>, nhóm <strong><a href=\"https://www.facebook.com/groups/toiuuweb/\" data-type=\"link\" data-id=\"https://www.facebook.com/groups/toiuuweb/\">Tối ưu web ✪</a></strong> để có được những kết nối tham gia.</p>\n\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:36:\"http://wellformedweb.org/CommentAPI/\";a:1:{s:10:\"commentRss\";a:1:{i:0;a:5:{s:4:\"data\";s:85:\"https://vi.wordpress.org/2023/07/22/recap-wordpress-meetup-ha-noi-thang-07-2023/feed/\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:38:\"http://purl.org/rss/1.0/modules/slash/\";a:1:{s:8:\"comments\";a:1:{i:0;a:5:{s:4:\"data\";s:1:\"0\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:7:\"post-id\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"1078\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}s:27:\"http://www.w3.org/2005/Atom\";a:1:{s:4:\"link\";a:1:{i:0;a:5:{s:4:\"data\";s:0:\"\";s:7:\"attribs\";a:1:{s:0:\"\";a:3:{s:4:\"href\";s:35:\"https://vi.wordpress.org/news/feed/\";s:3:\"rel\";s:4:\"self\";s:4:\"type\";s:19:\"application/rss+xml\";}}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:44:\"http://purl.org/rss/1.0/modules/syndication/\";a:2:{s:12:\"updatePeriod\";a:1:{i:0;a:5:{s:4:\"data\";s:9:\"\n	hourly	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}s:15:\"updateFrequency\";a:1:{i:0;a:5:{s:4:\"data\";s:4:\"\n	1	\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}s:30:\"com-wordpress:feed-additions:1\";a:1:{s:4:\"site\";a:1:{i:0;a:5:{s:4:\"data\";s:8:\"13096074\";s:7:\"attribs\";a:0:{}s:8:\"xml_base\";s:0:\"\";s:17:\"xml_base_explicit\";b:0;s:8:\"xml_lang\";s:0:\"\";}}}}}}}}}}}}s:4:\"type\";i:128;s:7:\"headers\";a:11:{s:6:\"server\";s:5:\"nginx\";s:4:\"date\";s:29:\"Sun, 19 Apr 2026 06:00:46 GMT\";s:12:\"content-type\";s:34:\"application/rss+xml; charset=UTF-8\";s:4:\"vary\";s:37:\"Accept-Encoding, accept, content-type\";s:6:\"x-olaf\";s:3:\"⛄\";s:13:\"last-modified\";s:29:\"Tue, 02 Dec 2025 20:00:00 GMT\";s:4:\"link\";s:61:\"<https://vi.wordpress.org/wp-json/>; rel=\"https://api.w.org/\"\";s:15:\"x-frame-options\";s:10:\"SAMEORIGIN\";s:16:\"content-encoding\";s:4:\"gzip\";s:7:\"alt-svc\";s:19:\"h3=\":443\"; ma=86400\";s:4:\"x-nc\";s:9:\"HIT ord 2\";}s:5:\"build\";i:1760618736;s:21:\"cache_expiration_time\";i:1776621646;s:23:\"__cache_expiration_time\";i:1776621646;}', 'off');
